216→void ULFPGameInstance::ApplyOwnedRelicsToUnit(ALFPTacticsUnit* Unit) const
217→{
218→	if (!Unit || !RelicDataAsset)
219→	{
220→		return;
221→	}
222→
223→	for (const FName& RelicID : OwnedRelicIDs)
224→	{
225→		FLFPRelicDefinition Definition;
226→		if (!FindRelicDefinition(RelicID, Definition))
227→		{
228→			continue;
229→		}
230→
231→		for (const FLFPRelicEffectEntry& Effect : Definition.Effects)
232→		{
233→			switch (Effect.EffectType)
234→			{
235→			case ELFPRelicEffectType::RET_MaxHealthFlat:
236→				Unit->AddCurrentMaxHealth(Effect.Value);
237→				break;
238→			case ELFPRelicEffectType::RET_AttackFlat:
239→				Unit->AddCurrentAttack(Effect.Value);
240→				break;
241→			case ELFPRelicEffectType::RET_DefenseFlat:
242→				Unit->AddCurrentPhysicalBlock(Effect.Value);
243→				break;
244→			case ELFPRelicEffectType::RET_SpeedFlat:
245→				Unit->AddCurrentSpeed(Effect.Value);
246→				break;
247→			default:
248→				break;
249→			}
250→		}
251→	}
252→}
