313→TArray<FLFPUnitEntry> ULFPGameInstance::GetMergeablePairs() const
314→{
315→	// 统计每个 TypeID 的出现次数
316→	TMap<FName, int32> CountMap;
317→
318→	for (const FLFPUnitEntry& Unit : PartyUnits)
319→	{
320→		if (Unit.IsValid())
321→		{
322→			CountMap.FindOrAdd(Unit.TypeID, 0)++;
323→		}
324→	}
325→	for (const FLFPUnitEntry& Unit : ReserveUnits)
326→	{
327→		if (Unit.IsValid())
328→		{
329→			CountMap.FindOrAdd(Unit.TypeID, 0)++;
330→		}
331→	}
332→
333→	// 筛选出现 >= 2 次且注册表中有进化目标的 TypeID
334→	TArray<FLFPUnitEntry> Result;
335→	for (const auto& Pair : CountMap)
336→	{
337→		if (Pair.Value >= 2 && UnitRegistry && UnitRegistry->CanEvolve(Pair.Key))
338→		{
339→			FLFPUnitEntry Entry;
340→			Entry.TypeID = Pair.Key;
341→			Entry.Tier = UnitRegistry->GetUnitTier(Pair.Key);
342→			Result.Add(Entry);
343→		}
344→	}
345→
346→	return Result;
347→}
