349→bool ULFPGameInstance::MergeUnits(bool bSourceAIsParty, int32 SourceAIndex,
350→	bool bSourceBIsParty, int32 SourceBIndex, FName TargetTypeID)
351→{
352→	TArray<FLFPUnitEntry>& ArrayA = bSourceAIsParty ? PartyUnits : ReserveUnits;
353→	TArray<FLFPUnitEntry>& ArrayB = bSourceBIsParty ? PartyUnits : ReserveUnits;
354→
355→	if (!ArrayA.IsValidIndex(SourceAIndex) || !ArrayB.IsValidIndex(SourceBIndex))
356→	{
357→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 无效的槽位索引"));
358→		return false;
359→	}
360→
361→	const FLFPUnitEntry& UnitA = ArrayA[SourceAIndex];
362→	const FLFPUnitEntry& UnitB = ArrayB[SourceBIndex];
363→
364→	// 验证两个源单位 TypeID 相同
365→	if (UnitA.TypeID != UnitB.TypeID)
366→	{
367→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 单位类型不匹配 (%s vs %s)"),
368→			*UnitA.TypeID.ToString(), *UnitB.TypeID.ToString());
369→		return false;
370→	}
371→
372→	// 验证 TargetTypeID 在进化目标列表中
373→	if (!UnitRegistry)
374→	{
375→		UE_LOG(LogTemp, Error, TEXT("MergeUnits: 注册表未配置"));
376→		return false;
377→	}
378→
379→	TArray<FName> Targets = UnitRegistry->GetEvolutionTargets(UnitA.TypeID);
380→	if (!Targets.Contains(TargetTypeID))
381→	{
382→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: %s 不是 %s 的有效进化目标"),
383→			*TargetTypeID.ToString(), *UnitA.TypeID.ToString());
384→		return false;
385→	}
386→
387→	// 创建进化后的新单位
388→	FLFPUnitEntry NewUnit;
389→	NewUnit.TypeID = TargetTypeID;
390→	NewUnit.Tier = UnitRegistry->GetUnitTier(TargetTypeID);
391→
392→	// 移除两个源单位（同一数组时先移除大索引避免偏移）
393→	if (bSourceAIsParty == bSourceBIsParty)
394→	{
395→		int32 First = FMath::Max(SourceAIndex, SourceBIndex);
396→		int32 Second = FMath::Min(SourceAIndex, SourceBIndex);
397→		ArrayA.RemoveAt(First);
398→		ArrayA.RemoveAt(Second);
399→	}
400→	else
401→	{
402→		ArrayA.RemoveAt(SourceAIndex);
403→		ArrayB.RemoveAt(SourceBIndex);
404→	}
405→
406→	TryAddUnit(NewUnit);
407→
408→	UE_LOG(LogTemp, Log, TEXT("进化成功: %s × 2 → %s (T%d)"),
409→		*UnitA.TypeID.ToString(), *TargetTypeID.ToString(), NewUnit.Tier);
410→
411→	return true;
412→}
