380→void ULFPUnitMergeWidget::OnMergeClicked()
381→{
382→	if (!CachedGameInstance || SlotA.bIsEmpty || SlotB.bIsEmpty) return;
383→	if (SelectedEvolutionTarget == NAME_None) return;
384→
385→	bool bSuccess = CachedGameInstance->MergeUnits(
386→		SlotA.bIsParty, SlotA.SlotIndex,
387→		SlotB.bIsParty, SlotB.SlotIndex,
388→		SelectedEvolutionTarget);
389→
390→	if (bSuccess)
391→	{
392→		UE_LOG(LogTemp, Log, TEXT("升阶 Widget: 进化成功 → %s"), *SelectedEvolutionTarget.ToString());
393→	}
394→
395→	ClearSlots();
396→	RefreshUnitIcons();
397→}
